import React, { useEffect, useState } from "react";
import { Bell, Check, CheckCheck } from "lucide-react";
import api from "../../api.js";
import "../dashboard/Dashboard.css";

export default function NotificationsPage() {
  const [notifications, setNotifications] = useState([]);
  const [filter, setFilter] = useState("all"); // all | unread | read
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let active = true;

    const load = async (showLoader = false) => {
      if (showLoader) setLoading(true);
      try {
        const res = await api.get("/notifications");
        if (!active) return;
        setNotifications(Array.isArray(res.data) ? res.data : []);
      } catch (err) {
        console.error(err);
      } finally {
        if (active) setLoading(false);
      }
    };

    load(true);
    const interval = setInterval(() => load(false), 5000);

    return () => {
      active = false;
      clearInterval(interval);
    };
  }, []);

  const handleMarkRead = async (id) => {
    await api.patch(`/notifications/${id}/read`);
    setNotifications((prev) => prev.map((n) => (n._id === id ? { ...n, read: true } : n)));
  };

  const handleMarkAllRead = async () => {
    await api.patch("/notifications/read-all");
    setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
  };

  const formatTime = (ts) => {
    const diff = Date.now() - new Date(ts).getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return "Just now";
    if (mins < 60) return `${mins} minutes ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs} hour${hrs > 1 ? "s" : ""} ago`;
    const days = Math.floor(hrs / 24);
    return `${days} day${days > 1 ? "s" : ""} ago`;
  };

  const filtered = notifications.filter((n) => {
    if (filter === "unread") return !n.read;
    if (filter === "read") return n.read;
    return true;
  });

  const unreadCount = notifications.filter((n) => !n.read).length;

  return (
    <div className="dashboardMain">
      <header className="dashboardHeader">
        <div className="headerBranding">
          <h1 className="logoText"><span>LEGALLENS</span> Notifications</h1>
          <p className="systemStatus">
            {unreadCount > 0 ? (
              <span><span className="highlightText">{unreadCount}</span> unread notification{unreadCount > 1 ? "s" : ""}</span>
            ) : (
              "All caught up!"
            )}
          </p>
        </div>
        {unreadCount > 0 && (
          <button className="primaryActionBtn" style={{ width: "auto", padding: "0.6rem 1.5rem" }} onClick={handleMarkAllRead}>
            <CheckCheck size={16} /> Mark all read
          </button>
        )}
      </header>

      {/* Filter Tabs */}
      <div className="notifFilterTabs">
        {["all", "unread", "read"].map((f) => (
          <button
            key={f}
            className={`notifFilterTab ${filter === f ? "notifFilterTabActive" : ""}`}
            onClick={() => setFilter(f)}
          >
            {f === "all" ? `All (${notifications.length})` : f === "unread" ? `Unread (${notifications.filter((n) => !n.read).length})` : `Read (${notifications.filter((n) => n.read).length})`}
          </button>
        ))}
      </div>

      {/* Notifications List */}
      <div className="notifPageList">
        {loading ? (
          <div className="notifLoadingState">
            <div className="notifLoadingSpinner" />
            <p>Loading notifications...</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="notifEmptyState">
            <Bell size={48} style={{ color: "#334155" }} />
            <p>No {filter !== "all" ? filter : ""} notifications</p>
          </div>
        ) : (
          filtered.map((n) => (
            <div key={n._id} className={`notifPageItem ${n.read ? "notifPageItemRead" : "notifPageItemUnread"}`}>
              <div className="notifPageDot" style={{ background: n.read ? "#22c55e" : "#ef4444" }} />
              <div className="notifPageContent">
                <p className="notifPageText">{n.message}</p>
                <span className="notifPageTime">{formatTime(n.created_at)}</span>
              </div>
              <div className="notifPageStatus">
                <span className={`notifStatusBadge ${n.read ? "notifStatusRead" : "notifStatusUnread"}`}>
                  {n.read ? "Read" : "Unread"}
                </span>
                {!n.read && (
                  <button className="notifMarkBtn" onClick={() => handleMarkRead(n._id)} title="Mark as read">
                    <Check size={14} />
                  </button>
                )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
